gWf(){return"\u062a\u0637\u0628\u064a\u0642 \u0627\u0644\u0639\u0645\u0631\u0629 \u0645\u0646\u0635\u0629 \u062a\u0631\u0628\u0637 \u0627\u0644\u0645\u0639\u062a\u0645\u0631\u064a\u0646 \u0628\u0648\u0643\u0627\u0644\u0627\u062a \u0633\u0641\u0631 \u0645\u0631\u062e\u0635\u0629. \u0627\u0644\u062d\u062c\u0648\u0632\u0627\u062a \u0639\u0628\u0631 \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0647\u064a \u0637\u0644\u0628\u0627\u062a: \u062a\u0642\u0648\u0645 \u0627\u0644\u0648\u0643\u0627\u0644\u0629 \u0628\u062a\u0623\u0643\u064a\u062f\u0647\u0627 \u0623\u0648 \u0631\u0641\u0636\u0647\u0627\u060c \u0648\u064a\u062a\u0645 \u0627\u0644\u062f\u0641\u0639 \u0645\u0628\u0627\u0634\u0631\u0629 \u0644\u062f\u0649 \u0627\u0644\u0648\u0643\u0627\u0644\u0629. \u062a\u0641\u0627\u0635\u064a\u0644 \u0627\u0644\u0628\u0627\u0642\u0627\u062a \u0648\u0627\u0644\u0623\u0633\u0639\u0627\u0631 \u0648\u0627\u0644\u062a\u0648\u0641\u0631 \u062a\u0642\u062f\u0645\u0647\u0627 \u0627\u0644\u0648\u0643\u0627\u0644\u0627\u062a \u0648\u0642\u062f \u062a\u062a\u063a\u064a\u0631.\n\n\u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645\u0643 \u0644\u0644\u062a\u0637\u0628\u064a\u0642 \u0641\u0625\u0646\u0643 \u062a\u0648\u0627\u0641\u0642 \u0639\u0644\u0649 \u062a\u0642\u062f\u064a\u0645 \u0645\u0639\u0644\u0648\u0645\u0627\u062a \u0635\u062d\u064a\u062d\u0629 \u0648\u0627\u0633\u062a\u062e\u062f\u0627\u0645 \u0627\u0644\u062e\u062f\u0645\u0629 \u0644\u0623\u063a\u0631\u0627\u0636 \u0634\u062e\u0635\u064a\u0629 \u0648\u0645\u0634\u0631\u0648\u0639\u0629 \u0641\u0642\u0637. \u0627\u0644\u062a\u0637\u0628\u064a\u0642 \u0644\u064a\u0633 \u0648\u0643\u0627\u0644\u0629 \u0633\u0641\u0631 \u0648\u0644\u064a\u0633 \u0637\u0631\u0641\u064b\u0627 \u0641\u064a \u0627\u0644\u0639\u0642\u062f \u0628\u064a\u0646\u0643 \u0648\u0628\u064a\u0646 \u0627\u0644\u0648\u0643\u0627\u0644\u0629."},
