gPk(){return"\u0626\u06d5\u0645\u06d5 \u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5\u062a \u0648 \u062d\u062c\u0632\u06d5\u06a9\u0627\u0646\u062a \u0648 \u0632\u0627\u0646\u06cc\u0627\u0631\u06cc\u06d5 \u067e\u0627\u0634\u06d5\u06a9\u06d5\u0648\u062a\u06a9\u0631\u0627\u0648\u06d5\u06a9\u0627\u0646\u062a \u0628\u06d5 \u06cc\u06d5\u06a9\u062c\u0627\u0631\u06cc \u062f\u06d5\u0633\u0695\u06ce\u062a\u06d5\u0648\u06d5. \u0646\u0627\u062a\u0648\u0627\u0646\u0631\u06ce\u062a \u0628\u06af\u06d5\u0695\u06ce\u0646\u0631\u06ce\u062a\u06d5\u0648\u06d5."},
gPl(){return"\u0628\u06d5\u06b5\u06ce\u060c \u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5\u0645 \u0628\u0633\u0695\u06d5\u0648\u06d5"},
gPp(){return"\u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5\u062a \u0633\u0695\u0627\u06cc\u06d5\u0648\u06d5."},
gPm(){return"\u0646\u06d5\u062a\u0648\u0627\u0646\u0631\u0627 \u0647\u06d5\u0698\u0645\u0627\u0631\u06d5\u06a9\u06d5 \u0628\u0633\u0695\u062f\u0631\u06ce\u062a\u06d5\u0648\u06d5. \u062f\u0648\u0648\u0628\u0627\u0631\u06d5 \u0647\u06d5\u0648\u06b5 \u0628\u062f\u06d5\u0631\u06d5\u0648\u06d5."},
