gRB(){return"\u0647\u06d5\u0698\u0645\u0627\u0631\u06ce\u06a9 \u062f\u0631\u0648\u0633\u062a \u0628\u06a9\u06d5 \u0628\u06c6 \u0628\u06b5\u0627\u0648\u06a9\u0631\u062f\u0646\u06d5\u0648\u06d5\u06cc \u06af\u06d5\u0634\u062a\u06d5\u06a9\u0627\u0646\u06cc \u0639\u0648\u0645\u0631\u06d5\u062a."},
